func TestCompactDiffFormatter_NilPlan(t *testing.T) {
	f := &CompactDiffFormatter{}
	got := f.Format(nil, nil)
	if got != "No changes.\n" {
		t.Errorf("expected 'No changes.\\n', got %q", got)
	}
}

func TestCompactDiffFormatter_NoChanges(t *testing.T) {
	plan := &plans.Plan{
		Changes: plans.NewChangesSrc(),
	}
	f := &CompactDiffFormatter{}
	got := f.Format(plan, nil)
	if got != "No changes.\n" {
		t.Errorf("expected 'No changes.\\n', got %q", got)
	}
}

func TestCompactDiffFormatter_SingleCreate(t *testing.T) {
	changes := plans.NewChangesSrc()
	changes.AppendResourceInstanceChange(&plans.ResourceInstanceChangeSrc{
		Addr: addrs.AbsResourceInstance{
			Module: addrs.RootModuleInstance,
			Resource: addrs.ResourceInstance{
				Resource: addrs.Resource{
					Mode: addrs.ManagedResourceMode,
					Type: "aws_instance",
					Name: "web",
				},
				Key: addrs.NoKey,
			},
		},
		DeposedKey: states.NotDeposed,
		ChangeSrc: plans.ChangeSrc{
			Action: plans.Create,
		},
	})
	plan := &plans.Plan{Changes: changes}

	f := &CompactDiffFormatter{}
	got := f.Format(plan, nil)

	if !strings.Contains(got, "create:") {
		t.Errorf("expected output to contain 'create:', got:\n%s", got)
	}
	if !strings.Contains(got, "aws_instance.web") {
		t.Errorf("expected output to contain 'aws_instance.web', got:\n%s", got)
	}
	if !strings.Contains(got, "Summary:") {
		t.Errorf("expected output to contain 'Summary:', got:\n%s", got)
	}
	if !strings.Contains(got, "create: 1") {
		t.Errorf("expected output to contain 'create: 1', got:\n%s", got)
	}
}

func TestCompactDiffFormatter_MultipleActions(t *testing.T) {
	changes := plans.NewChangesSrc()

	addChange := func(typ, name string, action plans.Action) {
		changes.AppendResourceInstanceChange(&plans.ResourceInstanceChangeSrc{
			Addr: addrs.AbsResourceInstance{
				Module: addrs.RootModuleInstance,
				Resource: addrs.ResourceInstance{
					Resource: addrs.Resource{
						Mode: addrs.ManagedResourceMode,
						Type: typ,
						Name: name,
					},
					Key: addrs.NoKey,
				},
			},
			DeposedKey: states.NotDeposed,
			ChangeSrc: plans.ChangeSrc{
				Action: action,
			},
		})
	}

	addChange("aws_instance", "web", plans.Create)
	addChange("aws_instance", "db", plans.Delete)
	addChange("aws_s3_bucket", "data", plans.Update)

	plan := &plans.Plan{Changes: changes}
	f := &CompactDiffFormatter{}
	got := f.Format(plan, nil)

	for _, want := range []string{
		"create:",
		"delete:",
		"update:",
		"aws_instance.web",
		"aws_instance.db",
		"aws_s3_bucket.data",
		"Summary:",
		"create: 1",
		"delete: 1",
		"update: 1",
	} {
		if !strings.Contains(got, want) {
			t.Errorf("expected output to contain %q, got:\n%s", want, got)
		}
	}
}

func TestCompactDiffFormatter_GroupsByAction(t *testing.T) {
	changes := plans.NewChangesSrc()

	for _, name := range []string{"a", "b", "c"} {
		changes.AppendResourceInstanceChange(&plans.ResourceInstanceChangeSrc{
			Addr: addrs.AbsResourceInstance{
				Module: addrs.RootModuleInstance,
				Resource: addrs.ResourceInstance{
					Resource: addrs.Resource{
						Mode: addrs.ManagedResourceMode,
						Type: "aws_instance",
						Name: name,
					},
					Key: addrs.NoKey,
				},
			},
			DeposedKey: states.NotDeposed,
			ChangeSrc: plans.ChangeSrc{
				Action: plans.Create,
			},
		})
	}

	plan := &plans.Plan{Changes: changes}
	f := &CompactDiffFormatter{}
	got := f.Format(plan, nil)

	// All three should appear under one "create:" section.
	createIdx := strings.Index(got, "create:")
	if createIdx == -1 {
		t.Fatalf("expected 'create:' in output, got:\n%s", got)
	}
	summaryIdx := strings.Index(got, "Summary:")
	if summaryIdx == -1 {
		t.Fatalf("expected 'Summary:' in output, got:\n%s", got)
	}

	section := got[createIdx:summaryIdx]
	for _, name := range []string{"a", "b", "c"} {
		addr := "aws_instance." + name
		if !strings.Contains(section, addr) {
			t.Errorf("expected %q in create section, got:\n%s", addr, section)
		}
	}

	if !strings.Contains(got, "create: 3") {
		t.Errorf("expected 'create: 3' in summary, got:\n%s", got)
	}
}

