package format

import (
	"fmt"
	"sort"
	"strings"

	"github.com/hashicorp/terraform/internal/plans"
	"github.com/hashicorp/terraform/internal/terraform"
)

// CompactDiffFormatter produces a condensed, summary-style diff output for a
// plan, showing only resource-level changes without attribute-level detail.
type CompactDiffFormatter struct{}

// Format returns a compact string representation of the given plan, showing
// one line per resource change grouped by action type, followed by summary
// counts.
func (f *CompactDiffFormatter) Format(plan *plans.Plan, schemas *terraform.Schemas) string {
	if plan == nil || plan.Changes == nil {
		return "No changes.\n"
	}

	// Collect changes by action group label.
	type entry struct {
		action plans.Action
		addr   string
	}

	var entries []entry
	for _, rc := range plan.Changes.Resources {
		if rc.Action == plans.NoOp {
			continue
		}
		entries = append(entries, entry{
			action: rc.Action,
			addr:   rc.Addr.String(),
		})
	}

	if len(entries) == 0 {
		return "No changes.\n"
	}

	// Sort entries: first by action label, then by address.
	sort.Slice(entries, func(i, j int) bool {
		li := actionLabel(entries[i].action)
		lj := actionLabel(entries[j].action)
		if li != lj {
			return li < lj
		}
		return entries[i].addr < entries[j].addr
	})

	// Group by action.
	groups := make(map[string][]string)
	var groupOrder []string
	seen := make(map[string]bool)
	for _, e := range entries {
		label := actionLabel(e.action)
		if !seen[label] {
			seen[label] = true
			groupOrder = append(groupOrder, label)
		}
		groups[label] = append(groups[label], e.addr)
	}
	sort.Strings(groupOrder)

	var buf strings.Builder
	for _, label := range groupOrder {
		addrs := groups[label]
		buf.WriteString(fmt.Sprintf("%s:\n", label))
		for _, addr := range addrs {
			buf.WriteString(fmt.Sprintf("  %s\n", addr))
		}
	}

	// Summary counts.
	counts := make(map[string]int)
	for _, e := range entries {
		counts[actionLabel(e.action)]++
	}
	buf.WriteString("\nSummary:\n")
	summaryLabels := make([]string, 0, len(counts))
	for label := range counts {
		summaryLabels = append(summaryLabels, label)
	}
	sort.Strings(summaryLabels)
	for _, label := range summaryLabels {
		buf.WriteString(fmt.Sprintf("  %s: %d\n", label, counts[label]))
	}

	return buf.String()
}

func actionLabel(action plans.Action) string {
	switch action {
	case plans.Create:
		return "create"
	case plans.Update:
		return "update"
	case plans.Delete:
		return "delete"
	case plans.DeleteThenCreate, plans.CreateThenDelete:
		return "replace"
	case plans.Read:
		return "read"
	case plans.Forget:
		return "forget"
	case plans.CreateThenForget:
		return "replace"
	default:
		return action.String()
	}
}
